import React, { useState } from "react";
import { Link, useLocation, useNavigate } from "react-router-dom";

import "./Menu.css";

const Menu = () => {
  const location = useLocation();
  const navigete = useNavigate();

  const [isOpen, setIsOpen] = useState(false);
  const [mode, setMode] = useState("login"); // login | register

  const [formData, setFormData] = useState({
    email: "",
    password: "",
    role: "organizer"
  });

  const items = [
    { name: "Головна", path: "/" },
    { name: "Події", path: "/events" },
    { name: "Новини", path: "/news" },
    { name: "Про нас", path: "/about" }
  ];

  // 🔥 РЕГИСТРАЦИЯ
  const handleRegister = async () => {
    try {
      const res = await fetch("http://localhost:5000/register", {
        method: "POST",
        headers: {
          "Content-Type": "application/json"
        },
        body: JSON.stringify(formData)
      });

      const data = await res.json();

      if (!res.ok) {
        alert(data.error);
        return;
      }

      alert("Реєстрація успішна 🎉");
      setMode("login");

    } catch (err) {
      console.error(err);
    }
  };

  // 🔥 ЛОГИН
  const handleLogin = async () => {
  try {
    const res = await fetch("http://localhost:5000/login", {
      method: "POST",
      headers: {
        "Content-Type": "application/json"
      },
      body: JSON.stringify({
        email: formData.email,
        password: formData.password
      })
    });

    const data = await res.json();

    if (!res.ok) {
      alert(data.error);
      return;
    }

    localStorage.setItem("user", JSON.stringify(data.user));

    setIsOpen(false);

    // 🔥 РЕДИРЕКТ
    if (data.user.role === "admin") {
      navigate("/admin");
    } else {
      navigate("/dashboard");
    }

  } catch (err) {
    console.error(err);
  }
};

  // 🔥 ОБЩИЙ SUBMIT
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!formData.email || !formData.password) {
      alert("Заповни всі поля");
      return;
    }

    if (mode === "login") {
      handleLogin();
    } else {
      handleRegister();
    }
  };

  return (
    <>
      <nav className="menu">
        <div className="menu-inner">

          <div className="logo">
            <Link to="/">SkillMeet</Link>
          </div>

          <ul>
            {items.map((item) => (
              <li key={item.name}>
                <Link
                  to={item.path}
                  className={location.pathname === item.path ? "active" : ""}
                >
                  {item.name}
                </Link>
              </li>
            ))}
          </ul>

          <button className="login-btn" onClick={() => setIsOpen(true)}>
            Увійти
          </button>

        </div>
      </nav>

      {/* 🔥 МОДАЛКА */}
      {isOpen && (
        <div className="modal-overlay" onClick={() => setIsOpen(false)}>
          <div className="modal" onClick={(e) => e.stopPropagation()}>

            <h2>{mode === "login" ? "Вхід" : "Реєстрація"}</h2>

            <form onSubmit={handleSubmit}>

              <input
                type="email"
                placeholder="Email"
                value={formData.email}
                onChange={(e) =>
                  setFormData({ ...formData, email: e.target.value })
                }
              />

              <input
                type="password"
                placeholder="Пароль"
                value={formData.password}
                onChange={(e) =>
                  setFormData({ ...formData, password: e.target.value })
                }
              />

              {/* 🔥 РОЛЬ ТОЛЬКО ПРИ РЕГИСТРАЦИИ */}
              {mode === "register" && (
                <select
                  value={formData.role}
                  onChange={(e) =>
                    setFormData({ ...formData, role: e.target.value })
                  }
                >
                  <option value="organizer">Організатор</option>
                  <option value="admin">Адміністратор</option>
                </select>
              )}

              <button type="submit">
                {mode === "login" ? "Увійти" : "Зареєструватися"}
              </button>
            </form>

            {/* 🔥 ПЕРЕКЛЮЧЕНИЕ */}
            <p className="switch-mode">
              {mode === "login"
                ? "Немає акаунта?"
                : "Вже є акаунт?"}

              <span
                onClick={() =>
                  setMode(mode === "login" ? "register" : "login")
                }
              >
                {mode === "login" ? " Реєстрація" : " Увійти"}
              </span>
            </p>

            <button className="close-btn" onClick={() => setIsOpen(false)}>
              Закрити
            </button>

          </div>
        </div>
      )}
    </>
  );
};

export default Menu;
